import math
import numpy as np
import pandas as pd


class PreProcessing:
    def __init__(self, x=None, params=None):
        """Initilize input data and parameters

        Args:
            x (array, optional): input timestamp and amplitude. array shape is to be (:,2). Defaults to None.
            params (dict, optional): parameters used in pre-processing. Defaults to None.
        """
        if x is not None:
            self.time = x[:, 0].reshape(-1)
            self.val = x[:, 1].reshape(-1)

        if params is not None:
            self.params = params

    def moving_average_filter(self, time, val, window_size):
        """Apply moving average filter to the signal. Return output as input if window_size is 0.

        Parameters
        ----------
        time : array-like
            Array of timestamps.
        val : array-like
            Array of signal amplitudes.
        window_size : int
            Window size of the moving average filter. If 0, the input is returned unchanged.

        Returns
        -------
        tuple of np.ndarray
            Filtered timestamps and filtered signal values.

        Examples
        --------
        >>> sp = SignalProcessing(x)
        >>> t_filt, v_filt = sp.moving_average_filter(sp.time, sp.val, window_size=3)
        """
        if window_size == 0:
            ouptut_time = time
            output_val = val
        else:
            temp = pd.Series(val)
            temp_mva = temp.rolling(window=window_size, center=True).mean()
            output_val = temp_mva[
                int(math.floor(window_size / 2)) : (
                    len(temp) - int(math.floor(window_size / 2))
                )
            ]
            output_val = np.array(output_val)

            ouptut_time = time[
                int(math.floor(window_size / 2)) : (
                    len(time) - int(math.floor(window_size / 2))
                )
            ]

        return ouptut_time, output_val

    def median_filter(self, time, val, window_size):
        """Apply median filter to the signal. Return output as input if window_size is 0.

        Parameters
        ----------
        time : array-like
            Array of timestamps.
        val : array-like
            Array of signal amplitudes.
        window_size : int
            Window size of the median filter. If 0, the input is returned unchanged.

        Returns
        -------
        tuple of np.ndarray
            Filtered timestamps and filtered signal values.

        Examples
        --------
        >>> sp = SignalProcessing(x)
        >>> t_med, v_med = sp.median_filter(sp.time, sp.val, window_size=3)
        """
        if window_size == 0:
            ouptut_time = time
            output_val = val
        else:
            temp = pd.Series(val)
            temp_bl = temp.rolling(
                window=window_size, center=True
            ).median()  # median filter
            output_val = temp_bl[
                int(math.floor(window_size / 2)) : (
                    len(temp) - int(math.floor(window_size / 2))
                )
            ]
            output_val = np.array(output_val)

            ouptut_time = time[
                int(math.floor(window_size / 2)) : (
                    len(time) - int(math.floor(window_size / 2))
                )
            ]
        return ouptut_time, output_val
